-- Quick sanity checks
SELECT 'access_logs_count' AS metric, COUNT(*) AS value
FROM access_logs
WHERE agent_hash IN (
  '11111111111111111111111111111111',
  '22222222222222222222222222222222',
  '33333333333333333333333333333333',
  '44444444444444444444444444444444'
)
UNION ALL
SELECT 'access_logs_daily_count' AS metric, COUNT(*) AS value
FROM access_logs_daily
WHERE agent_hash IN (
  '11111111111111111111111111111111',
  '22222222222222222222222222222222',
  '33333333333333333333333333333333',
  '44444444444444444444444444444444'
)
UNION ALL
SELECT 'user_agents_count' AS metric, COUNT(*) AS value
FROM user_agents
WHERE hash IN (
  '11111111111111111111111111111111',
  '22222222222222222222222222222222',
  '33333333333333333333333333333333',
  '44444444444444444444444444444444'
);
